static void pcibase_realize(PCIDevice *pdev, Error **errp)
{
    PCIBaseState *s = PCIBASE_DEVICE(pdev);
    uint8_t *pci_conf = pdev->config;

    /* Configure PCI IDs to something stable; the Linux driver will
     * match based on the f81601_pci_tbl in the guest, but here we just
     * provide generic values (actual IDs are not present in snippet). */
    pci_config_set_vendor_id(pci_conf, 0x1C29); /* Example: Fintek vendor */
    pci_config_set_device_id(pci_conf, 0x1601); /* Example device ID */
    pci_config_set_class(pci_conf, PCI_CLASS_COMMUNICATION_SERIAL);
    pci_config_set_revision(pci_conf, 0x01);

    /* Use legacy INTx only: driver uses pdev->irq and IRQF_SHARED. */
    pci_config_set_interrupt_pin(pci_conf, 1);

    s->has_msi = false;
    s->has_msix = false;

    /* Setup BAR0 as MMIO with size covering up to two channels. */
    s->num_bars = 1;
    s->bar_info[0].index = 0;
    s->bar_info[0].type = BAR_TYPE_MMIO;
    s->bar_info[0].size = F81601_BAR0_SIZE;
    s->bar_info[0].name = "f81601-bar0";
    s->bar_info[0].sparse = false;

    for (int i = 1; i < 6; i++) {
        s->bar_info[i].index = i;
        s->bar_info[i].type = BAR_TYPE_NONE;
        s->bar_info[i].size = 0;
        s->bar_info[i].name = NULL;
        s->bar_info[i].sparse = false;
    }

    /* Allocate linear backing for BAR0 */
    s->mmio_backing_size = F81601_BAR0_SIZE;
    s->mmio_backing = g_malloc0(s->mmio_backing_size);

    /* Register BARs */
    for (int i = 0; i < s->num_bars; i++) {
        pcibase_register_bar(pdev, s, &s->bar_info[i], errp);
        if (errp && *errp) {
            return;
        }
    }

    /* Per-channel base offsets */
    for (int i = 0; i < F81601_PCI_MAX_CHAN; i++) {
        s->chan_base[i] = (hwaddr)(F81601_CHANNEL_STRIDE * i);
    }

    /* Initialize trap register such that CAN2 is present by default. */
    s->trap_reg = F81601_CAN2_HAS_EN;
    pdev->config[F81601_TRAP_REG] = s->trap_reg;

    /* Initial decode register: enable IO, MEM, CFG, both CAN channels. */
    s->decode_reg = F81601_IO_MODE | F81601_MEM_MODE | F81601_CFG_MODE |
                    F81601_CAN2_EN | F81601_CAN1_EN;
    pdev->config[F81601_DECODE_REG] = s->decode_reg;

    /* DMA init (none for this device) */
    pcibase_dma_device_realize(pdev, errp);
    if (errp && *errp) {
        return;
    }


    s->num_channels = F81601_PCI_MAX_CHAN;
    s->initialized = true;
}

